32	  userList,
33	  // cylceOptions,
34	  // objectiveOptions,
35	  cylce,
36	  setInitiativeVisible,
37	}) => {
38	  const { t } = isReadServerTextData
39	    ? useLocaleTranslation()
40	    : useTranslation(['initiatives', 'common'])
41	  const {
42	    initiativeGeneralInfo,
43	    modelStep,
44	    isModelEdit,
