55	  const [approveModalVisible, setApproveModalVisible] = useState(false)
56	  const [visibleReject, setVisibleReject] = useState(false)
57	  const [rejectRemark, setRejectRemark] = useState('')
58	  const [approveType, setApproveType] = useState('')
59	  const location = useLocation()
60	  const checkPermission = useCheckPermission()
61	  const canInitiativeSubmit = checkPermission(InitiativePermissionEnum.SUBMIT)
62	
63	  const setApproveVisible = (status: boolean, flag: string) => {
64	    setApproveModalVisible(status)
65	    if (flag === 'ok') {
66	      // 审批通过
67	      const InitiativeApproveData = {
68	        id,
69	        result: 1,
70	        remark: '',
71	      }
72	      runInitiativeApprove(InitiativeApproveData)
73	    }
74	  }
75	
76	  const debouncedInitiativeSubmit = useDebouncedPromise(initiativeSubmit, 500)
77	  const { loading, runAsync: runInitiativeSubmit } = useRequest(
78	    debouncedInitiativeSubmit,
79	    {
80	      manual: true,
81	      onSuccess: () => {
82	        if (isModelEdit) {
83	          setInitiativeVisible(false)
