import { Button, Modal, Input, Message } from '@arco-design/web-react'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { initiativeSubmit, initiativeApprove } from '@/service'
import { useRequest } from 'ahooks'
import useInitiativeInfo from '../../hooks/useInitiativeInfo'
import { useNavigate, useLocation } from 'react-router-dom'
import PageWrapper from '@common/components/PageWrapper'
import StepBar from '@common/components/StepBar/StepBar'
import { InitiativesStep } from '@/constants/initiatives'
import classNames from 'classnames'
import InitiativesAddForm from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesAddAndEdit/InitiativesAddForm'
import ActivitySettingTable from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesActivity/ActivitySettingTable'
import FinishedTable from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesFinished/FinishedTable'
import FinishedTableModal from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesFinishedModal/FinishedTableModal'
import { useState, useEffect } from 'react'
import { InitiativesStatusEnum } from '@/constants/initiatives'
import InitiativeApproveModal from './InitiativeApproveModal'
import _ from 'lodash'
import { MaxLengthEnum } from '@common/constants/maxLength'
import './style/index.less'
import '@/pages/Initiatives/InitiativesMgmt/index.less'
import { IconLoading } from '@arco-design/web-react/icon'
import { initiativeDetail } from '@/service'
import { InitiativePermissionEnum } from '@/constants/permission'
import useCheckPermission from '@common/hooks/useCheckPermission'
import { useConditionalButton } from '@common/hooks/useConditionalRender'
const TextArea = Input.TextArea
const FinishedBtn = ({
  userList,
  // cylceOptions,
  // objectiveOptions,
  cylce,
  setInitiativeVisible,
}) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['initiatives', 'common'])
  const {
    initiativeGeneralInfo,
    modelStep,
    isModelEdit,
    cycleStatus,
    setModelStatus,
    setModelStep,
    getInitiativeGeneralInfo,
    setInitiativeGeneral,
    setActivityInfo,
  } = useInitiativeInfo()
  const { id, status, needApproval } = initiativeGeneralInfo
  const navigate = useNavigate()
  const [initiativeInfoVisible, setInitiativeInfoVisible] = useState(false)
  const [approveModalVisible, setApproveModalVisible] = useState(false)
  const [visibleReject, setVisibleReject] = useState(false)
  const [rejectRemark, setRejectRemark] = useState('')
  const [approveType, setApproveType] = useState('')
  const location = useLocation()
  const checkPermission = useCheckPermission()
  const canInitiativeSubmit = checkPermission(InitiativePermissionEnum.SUBMIT)

  const setApproveVisible = (status: boolean, flag: string) => {
    setApproveModalVisible(status)
    if (flag === 'ok') {
      // 审批通过
      const InitiativeApproveData = {
        id,
        result: 1,
        remark: '',
      }
      runInitiativeApprove(InitiativeApproveData)
    }
  }

  const debouncedInitiativeSubmit = useDebouncedPromise(initiativeSubmit, 500)
  const { loading, runAsync: runInitiativeSubmit } = useRequest(
    debouncedInitiativeSubmit,
    {
      manual: true,
      onSuccess: () => {
        if (isModelEdit) {
          setInitiativeVisible(false)
          setModelStep(1)
          setModelStatus(false)
        } else {
          // navigate(`/initiatives/initiatives-mgmt`)
          handleCancel()
        }
        Message.success(t('common:message.submitSuccessfully'))
      },
    },
  )
  //审批通过
  const debouncedInitiativeApprove = useDebouncedPromise(initiativeApprove, 500)
  const { loading: rejectLoading, runAsync: runInitiativeApprove } = useRequest(
    debouncedInitiativeApprove,
    {
      manual: true,
      onSuccess: () => {
        if (approveType === 'approve') {
          Message.success(t('common:message.approveSuccessfully'))
          setApproveModalVisible(false)
        } else {
          Message.success(t('common:message.rejectSuccessfully'))
          setVisibleReject(false)
        }
        //approve or reject return to list page
        // navigate(`/initiatives/initiatives-mgmt`)
        // getInitiativeGeneralInfo(id)
        handleCancel()
      },
    },
  )
  //审批不通过
  const rejectInitiative = () => {
    const InitiativeRejectData = {
      id,
      result: 0,
      remark: rejectRemark,
    }
    runInitiativeApprove(InitiativeRejectData)
  }

  // Edit弹出是请求detai接口
  const { loading: detailLoading, runAsync: runInitiativeDetail } = useRequest(
    initiativeDetail,
    {
      manual: true,
      onSuccess: (res) => {
        const initiativeGeneralInfo = {
          ...res['initiativeGeneralInfo'],
          ...res['orgInfo'],
        }
        setInitiativeGeneral(initiativeGeneralInfo)
        setActivityInfo(res['initiativeActivities'])
        setModelStatus(true)
      },
    },
  )

  const handleBack = () => {
    if (isModelEdit) {
      setModelStep(2)
    } else {
      navigate(`/initiatives/initiatives-mgmt/edit/2/${id}`)
    }
  }
  const handleInitiativeModelForm = () => {
    setInitiativeInfoVisible(true) //先出现弹框，后出现加载loading
    runInitiativeDetail(id)
  }

  const stepOptions = [
    { title: t('initiatives:initiativeInfo.initiativeStepOne') },
    { title: t('initiatives:initiativeInfo.initiativeStepTwo') },
    { title: t('initiatives:initiativeInfo.initiativeStepThree') },
  ]

  const handleCancel = () => {
    if (location?.state?.locationFrom === 'initiative') {
      navigate(`/initiatives/activities/list`, { state: { from: 'detail' } })
    } else if (location?.state?.locationFrom === 'initiativeBudget') {
      navigate(`/budget/initiatives/list`, { state: { from: 'detail' } })
    } else {
      navigate(`/initiatives/initiatives-mgmt/list`, {
        state: { from: 'detail' },
      })
    }
  }

  const initiativeLastSubmit = () => {
    runInitiativeSubmit(id)
  }
  const handleInitiativeReject = () => {
    setApproveType('reject')
    setVisibleReject(true)
  }
  // 审批通过
  const handleInitiativeApprove = () => {
    setApproveModalVisible(true)
    setApproveType('approve')
  }

  const getRejectRemarkValue = (value) => {
    setRejectRemark(value)
  }
  return (
    <>
      <div className='add-initiative-button'>
        {/* padding approve 状态下出现的按钮 */}
        {status !== InitiativesStatusEnum.Draft ? (
          <>
            <Button
              onClick={async () => {
                try {
                  handleCancel()
                } catch (e) {}
              }}
            >
              {status === InitiativesStatusEnum.Published
                ? t('common:btn.close')
                : t('common:btn.cancel')}
            </Button>

            {/* 如果是拒绝打回的单子 只有Initiative Creator可以修改 */}
            {status === InitiativesStatusEnum.RevisionRequired &&
              useConditionalButton(
                <>
                  <Button
                    type='primary'
                    onClick={async () => {
                      try {
                        handleInitiativeModelForm()
                      } catch (e) {
                        console.log('error', e)
                      }
                    }}
                  >
                    {t('common:btn.edit')}
                  </Button>
                  {canInitiativeSubmit && (
                    <Button
                      loading={loading}
                      type='primary'
                      onClick={async () => {
                        try {
                          initiativeLastSubmit()
                        } catch (e) {
                          console.log('error', e)
                        }
                      }}
                    >
                      {t('common:btn.submit')}
                    </Button>
                  )}
                </>,
                cycleStatus,
              )}

            {/* 是否需要needApprove */}
            {needApproval &&
              useConditionalButton(
                <>
                  <Button
                    type='primary'
                    onClick={async () => {
                      try {
                        handleInitiativeModelForm()
                      } catch (e) {
                        console.log('error', e)
                      }
                    }}
                  >
                    {t('common:btn.edit')}
                  </Button>
                  <Button
                    type='primary'
                    status='danger'
                    onClick={async () => {
                      try {
                        handleInitiativeReject()
                      } catch (e) {
                        console.log('error', e)
                      }
                    }}
                  >
                    {t('common:btn.reject')}
                  </Button>
                  <Button
                    type='primary'
                    status='success'
                    onClick={async () => {
                      try {
                        handleInitiativeApprove()
                      } catch (e) {
                        console.log('error', e)
                      }
                    }}
                  >
                    {t('common:btn.approve')}
                  </Button>
                </>,
                cycleStatus,
              )}
          </>
        ) : (
          <>
            <Button
              onClick={async () => {
                try {
                  handleBack()
                } catch (e) {}
              }}
            >
              {t('common:btn.back')}
            </Button>

            <Button
              onClick={async () => {
                try {
                  handleCancel()
                } catch (e) {}
              }}
            >
              {t('common:btn.cancel')}
            </Button>
            {/* admin 直接提交initiative 出现的submit 按钮 */}
            {canInitiativeSubmit && (
              <Button
                loading={loading}
                type='primary'
                onClick={async () => {
                  try {
                    // 页面状态的submit
                    initiativeLastSubmit()
                  } catch (e) {
                    console.log('error', e)
                  }
                }}
              >
                {t('common:btn.submit')}
              </Button>
            )}
          </>
        )}
      </div>

      {/* 弹框模块 */}
      <Modal
        title={t('initiatives:editInitiative')}
        visible={initiativeInfoVisible}
        style={{ width: 1160 }}
        autoFocus={false}
        focusLock={true}
        footer={null}
        closable={true}
        onCancel={() => {
          setInitiativeInfoVisible(false) //当前页面的关闭，只能用当前的方法
          setModelStep(1)
          setModelStatus(false)
        }}
      >
        <div className='initiatives-mgmt'>
          <PageWrapper
            resetMarginTop={true}
            resetPageWrapperPadding={true}
            headerTitle={t('initiatives:upperAddInitiatives')}
            showHeader={!isModelEdit}
          >
            <div className='initiatives-content'>
              <div className='step'>
                <StepBar
                  current={modelStep}
                  style={{ width: '548px' }}
                  stepOptions={stepOptions}
                />
              </div>
              {detailLoading ? (
                <div className='is-form-loading'>
                  <IconLoading style={{ width: 32, height: 32 }} />
                </div>
              ) : (
                <>
                  {modelStep === InitiativesStep.STEPONE && (
                    <div
                      className={classNames({
                        [`step-1`]: true,
                        // [`mt20`]: status !== ProjectReleaseStatusEnum.Draft,
                      })}
                    >
                      <InitiativesAddForm
                        userList={userList}
                        cylce={cylce}
                        setInitiativeInfoVisible={setInitiativeInfoVisible}
                      />
                    </div>
                  )}
                  {modelStep === InitiativesStep.STEPTWO && (
                    <div className='step-2'>
                      <div className='activities-setting-table-box'>
                        <ActivitySettingTable
                          userList={userList}
                          setInitiativeInfoVisible={setInitiativeInfoVisible}
                        />
                      </div>
                    </div>
                  )}
                  {modelStep === InitiativesStep.STEPTHREE && (
                    <div
                      className={classNames({
                        [`step-3`]: true,
                        // [`mt20`]: status !== ProjectReleaseStatusEnum.Draft,
                      })}
                    >
                      {isModelEdit ? (
                        <FinishedTableModal
                          setInitiativeVisible={setInitiativeInfoVisible}
                        />
                      ) : (
                        <FinishedTable />
                      )}
                    </div>
                  )}
                </>
              )}
            </div>
          </PageWrapper>
        </div>
      </Modal>
      {/* 审批approve */}
      <InitiativeApproveModal
        approveModalVisible={approveModalVisible}
        setApproveVisible={setApproveVisible}
      />
      {/* 审批拒绝的弹框 */}
      <Modal
        alignCenter={true}
        // style={{ top: 100}}
        title={t('project:reasonForRejection')}
        visible={visibleReject}
        onCancel={() => setVisibleReject(false)}
        autoFocus={false}
        focusLock={true}
        closable={true}
        footer={
          <>
            <Button onClick={() => setVisibleReject(false)}>
              {t('common:btn.cancel')}
            </Button>
            <Button
              loading={rejectLoading}
              onClick={() => rejectInitiative()}
              type='primary'
              status='danger'
            >
              {t('common:btn.reject')}
            </Button>
          </>
        }
      >
        <TextArea
          allowClear
          showWordLimit
          maxLength={MaxLengthEnum.TextArea}
          placeholder={t('common:pleaseEnter')}
          onChange={(c) => getRejectRemarkValue(c)}
        />
      </Modal>
    </>
  )
}
export default FinishedBtn

