import { useSelector } from 'react-redux'
import { RootState } from '@/store'
import { UserState } from '@common/store/slices/user.ts'
import { RoleIconsEnum } from '@/constants/roleManagement.ts'

export const useIsAdmin = () => {
  const { roleInfo } = useSelector<RootState, UserState>((state) => state.user)
  const currentRoleInfo = roleInfo as any

  if (currentRoleInfo?.length) {
    for (let i = 0; i < currentRoleInfo.length; i++) {
      if (currentRoleInfo[i].roleId == RoleIconsEnum.ADMIN) {
        return true
      }
    }
  }
  return false
}

export const useIsProjectAdmin = () => {
  const { roleInfo } = useSelector<RootState, UserState>((state) => state.user)
  const currentRoleInfo = roleInfo as any

  if (currentRoleInfo?.length) {
    for (let i = 0; i < currentRoleInfo.length; i++) {
      if (currentRoleInfo[i].roleId == RoleIconsEnum.PROJECT_ADMIN) {
        return true
      }
    }
  }
  return false
}

export const useIsInitiativeAdmin = () => {
  const { roleInfo } = useSelector<RootState, UserState>((state) => state.user)
  const currentRoleInfo = roleInfo as any

  if (currentRoleInfo?.length) {
    for (let i = 0; i < currentRoleInfo.length; i++) {
      if (currentRoleInfo[i].roleId == RoleIconsEnum.INITIATIVE_ADMIN) {
        return true
      }
    }
  }
  return false
}

export const useIsKpiAdmin = () => {
  const { roleInfo } = useSelector<RootState, UserState>((state) => state.user)
  const currentRoleInfo = roleInfo as any

  if (currentRoleInfo?.length) {
    for (let i = 0; i < currentRoleInfo.length; i++) {
      if (currentRoleInfo[i].roleId == RoleIconsEnum.KPI_ADMIN) {
        return true
      }
    }
  }
  return false
}

