    url: `/api/approval/queryApprovalHistory/${bizId}`,
    method: 'get',
  })
}

/**
 * @description 发布状态的initiative 编辑
 * @param params
 * @returns
 */
export async function initiativeInfoEdit(data) {
  return http.request<object>({
    url: '/api/initiative/edit',
    method: 'post',
    data,
  })
}

/**
 * @description 导出initiative list
 * @param params
 * @returns
 */
export async function exportInitiativeListRequest(data) {
  return http.request<object>({
    url: '/api/initiative/export',
    method: 'post',
    responseType: 'blob',
    data,
  })
}

// 获取 initiative的历史操作记录
export async function getInitiativeHistory(data) {
  return http.request<object>({
    url: `/api/operation-log/initiativeLog`,
    method: 'post',
    data,
  })
}

// 修改 budget
export async function initiativeBudgetEdit(data) {
  return http.request<object>({
    url: `/api/initiative/editBudget`,
    method: 'post',
    data,
  })
}

// initiative Activity import excel
export async function initiativeActivityImportExcel(data) {
  return http.request<object>({
    url: '/api/initiative/activity/import',
    method: 'post',
    data,
  })
}

// initiative Activity import excel
export async function initiativeChangeResponsiblePerson(data) {
  return http.request<object>({
    url: '/api/initiative/activity/changeHead',
    method: 'post',
    data,
  })
}

