2	import { useTranslation } from 'react-i18next'
3	import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
4	import { isReadServerTextData } from '@common/constants/env'
5	import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
6	import { useIsAdmin, useIsInitiativeAdmin } from '@common/hooks/useIsAdmin'
7	import { initiativeSubmit, initiativeApprove, initiativeReturn } from '@/service'
8	import { useRequest } from 'ahooks'
9	import useInitiativeInfo from '../../hooks/useInitiativeInfo'
10	import { useNavigate, useLocation } from 'react-router-dom'
11	import PageWrapper from '@common/components/PageWrapper'
12	import StepBar from '@common/components/StepBar/StepBar'
13	import { InitiativesStep } from '@/constants/initiatives'
14	import classNames from 'classnames'
15	import InitiativesAddForm from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesAddAndEdit/InitiativesAddForm'
16	import ActivitySettingTable from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesActivity/ActivitySettingTable'
17	import FinishedTable from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesFinished/FinishedTable'
18	import FinishedTableModal from '@/pages/Initiatives/InitiativesMgmt/components/InitiativesFinishedModal/FinishedTableModal'
19	import { useState, useEffect } from 'react'
20	import { InitiativesStatusEnum } from '@/constants/initiatives'
21	import InitiativeApproveModal from './InitiativeApproveModal'
22	import _ from 'lodash'
23	import { MaxLengthEnum } from '@common/constants/maxLength'
24	import './style/index.less'
25	import '@/pages/Initiatives/InitiativesMgmt/index.less'
26	import { IconLoading } from '@arco-design/web-react/icon'
27	import { initiativeDetail } from '@/service'
28	import { InitiativePermissionEnum } from '@/constants/permission'
29	import useCheckPermission from '@common/hooks/useCheckPermission'
30	import { useConditionalButton } from '@common/hooks/useConditionalRender'
31	const TextArea = Input.TextArea
32	const FinishedBtn = ({
33	  userList,
34	  // cylceOptions,
35	  // objectiveOptions,
36	  cylce,
37	  setInitiativeVisible,
38	}) => {
39	  const { t } = isReadServerTextData
40	    ? useLocaleTranslation()
41	    : useTranslation(['initiatives', 'common'])
42	  const {
43	    initiativeGeneralInfo,
44	    modelStep,
45	    isModelEdit,
46	    cycleStatus,
47	    setModelStatus,
48	    setModelStep,
49	    getInitiativeGeneralInfo,
50	    setInitiativeGeneral,
51	    setActivityInfo,
52	  } = useInitiativeInfo()
53	  const { id, status, needApproval } = initiativeGeneralInfo
54	  const navigate = useNavigate()
55	  const [initiativeInfoVisible, setInitiativeInfoVisible] = useState(false)
56	  const [approveModalVisible, setApproveModalVisible] = useState(false)
57	  const [visibleReject, setVisibleReject] = useState(false)
58	  const [rejectRemark, setRejectRemark] = useState('')
59	  const [approveType, setApproveType] = useState('')
60	  const [visibleReturn, setVisibleReturn] = useState(false)
61	  const [returnRemark, setReturnRemark] = useState('')
62	  const isAdmin = useIsAdmin()
63	  const isInitiativeAdmin = useIsInitiativeAdmin()
64	  const canAdminReturn =
65	    (isAdmin || isInitiativeAdmin) &&
66	    status === InitiativesStatusEnum.PendingApproval
67	  const location = useLocation()
68	  const checkPermission = useCheckPermission()
69	  const canInitiativeSubmit = checkPermission(InitiativePermissionEnum.SUBMIT)
70	
71	  const setApproveVisible = (status: boolean, flag: string) => {
72	    setApproveModalVisible(status)
73	    if (flag === 'ok') {
74	      // 审批通过
75	      const InitiativeApproveData = {
76	        id,
77	        result: 1,
78	        remark: '',
79	      }
80	      runInitiativeApprove(InitiativeApproveData)
81	    }
82	  }
83	
84	  const debouncedInitiativeSubmit = useDebouncedPromise(initiativeSubmit, 500)
85	  const { loading, runAsync: runInitiativeSubmit } = useRequest(
86	    debouncedInitiativeSubmit,
87	    {
88	      manual: true,
89	      onSuccess: () => {
90	        if (isModelEdit) {
91	          setInitiativeVisible(false)
92	          setModelStep(1)
93	          setModelStatus(false)
94	        } else {
95	          // navigate(`/initiatives/initiatives-mgmt`)
96	          handleCancel()
97	        }
98	        Message.success(t('common:message.submitSuccessfully'))
99	      },
100	    },
101	  )
102	  //审批通过
103	  const debouncedInitiativeApprove = useDebouncedPromise(initiativeApprove, 500)
104	  const { loading: rejectLoading, runAsync: runInitiativeApprove } = useRequest(
105	    debouncedInitiativeApprove,
106	    {
107	      manual: true,
108	      onSuccess: () => {
109	        if (approveType === 'approve') {
110	          Message.success(t('common:message.approveSuccessfully'))
111	          setApproveModalVisible(false)
112	        } else {
113	          Message.success(t('common:message.rejectSuccessfully'))
114	          setVisibleReject(false)
115	        }
116	        //approve or reject return to list page
117	        // navigate(`/initiatives/initiatives-mgmt`)
118	        // getInitiativeGeneralInfo(id)
119	        handleCancel()
120	      },
121	    },
122	  )
123	  //审批不通过
124	  const rejectInitiative = () => {
125	    const InitiativeRejectData = {
