import React from 'react'
import { Button, Message, Modal } from '@arco-design/web-react'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import './style/index.less'
import {
  projectInfoAdd,
  projectInfoAddCopy,
  projectPmInfoAddCopy,
} from '@/service'
import { useRequest } from 'ahooks'
import useProjectInfo from '../../hooks/useProjectInfo'
import { useNavigate, useParams } from 'react-router-dom'
import { useState } from 'react'
import { ProjectPublishedEnum } from '@/constants/project'
import { ProjectPermissionEnum } from '@/constants/permission'
import useCheckPermission from '@common/hooks/useCheckPermission'
import { isReadServerTextData } from '@common/constants/env'
import useUserInfo from '@common/hooks/useUserInfo'
import { useIsAdmin, useIsProjectAdmin } from '@common/hooks/useIsAdmin.ts'
import _ from 'lodash'

type Props = {
  form: any
  projectDetailName: string
  projectDetailNameAr: string
  isDirty?: boolean
  onMarkSaved?: () => void
  /** 手动 Save/Submit 前调用，让父组件清除自动保存定时器，防止保存成功清空 draft 后定时器触发创建重复记录 */
  onBeforeSave?: () => void
  autoSaveStatus?: 'idle' | 'unsaved' | 'saving' | 'saved' | 'error'
  lastSavedTime?: string
  autoSaveProjectIdRef?: React.MutableRefObject<string>
}

const ProjectAddFormBtn = ({
  form,
  projectDetailName,
  projectDetailNameAr,
  isDirty = false,
  onMarkSaved,
  onBeforeSave,
  autoSaveStatus = 'idle',
  lastSavedTime = '',
  autoSaveProjectIdRef,
}: Props) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['project', 'common'])

  const {
    projectDetailInfo,
    milestoneActivities,
    setProjectInfoId,
    setProjectInfo,
    getProjectDetailInfo,
    setProjectMilestoneInfo,
  } = useProjectInfo()

  const { pedit } = useParams()
  const isProjectPublishedEdit =
    Number(pedit) === ProjectPublishedEnum.PublishedProjectEdit ? true : false
  const { id: storeId, name, projectManager } = projectDetailInfo
  // auto-save 创建的草稿 ID 优先于 Redux store 中的 ID（避免 setProjectInfoId 清空表单）
  const id = autoSaveProjectIdRef?.current || storeId
  const [isCompleted, setIsCompleted] = useState(false)
  const [saveLoading, setSaveLoading] = useState(false)
  const [submitLoading, setSubmitLoading] = useState(false)

  const navigate = useNavigate()
  const checkPermission = useCheckPermission()
  const canProjectSave = checkPermission(ProjectPermissionEnum.SAVE)
  const canPmEdit = checkPermission(ProjectPermissionEnum.PmEdit)
  const isAdmin = useIsAdmin()
  const isProjectAdmin = useIsProjectAdmin()
  const isPm = projectManager == useUserInfo().userId

  const InfoAddCopy = () => {
    if (isProjectPublishedEdit) {
      if (isAdmin || isProjectAdmin) {
        return projectInfoAddCopy
      } else if (isPm) {
        return projectPmInfoAddCopy
      } else {
        return projectInfoAddCopy
      }
    } else {
      return projectInfoAdd
    }
  }

  const debouncedProjectInfoAdd = useDebouncedPromise(InfoAddCopy(), 500)
  const { runAsync: runProjectInfoAdd } = useRequest(debouncedProjectInfoAdd, {
    manual: true,
    onSuccess: (res) => {
      Message.success(
        isCompleted
          ? t('common:message.submitSuccessfully')
          : t('common:message.saveSuccessfully'),
      )
      // 通知父组件手动保存已完成，重置 dirty 状态
      onMarkSaved?.()

      setProjectInfoId(res)
      if (isCompleted) {
        setProjectMilestoneInfo(milestoneActivities)
        isProjectPublishedEdit
          ? navigate(`/projects/projects-mgmt/edit/2/${res}/1`)
          : navigate(`/projects/projects-mgmt/edit/2/${res}`)
      } else {
        const projectManagerNew = projectManager ? projectManager[0] : ''
        form.setFieldsValue({
          ...projectDetailInfo,
          projectManager: projectManagerNew,
        })
        isProjectPublishedEdit
          ? navigate(`/projects/projects-mgmt/edit/1/${res}/1`)
          : navigate(`/projects/projects-mgmt/edit/1/${res}`)
      }
    },
    onFinally: () => {
      setSaveLoading(false)
      setSubmitLoading(false)
    },
  })

  // 走表单校验
  const handleSubmitProjectInfo = () => {
    onBeforeSave?.()   // 清除挂起的自动保存定时器
    form
      .validate()
      .then(() => {
        const fields = form.getFieldsValue()
        const projectManagerObj =
          typeof fields.projectManager === 'string'
            ? fields.projectManager
              ? [fields.projectManager]
              : []
            : fields.projectManager

        const ProjectSaveFormData = {
          ...fields,
          projectManager: projectManagerObj,
          id,
          isCompleted: true,
        }
        setSubmitLoading(true)
        setIsCompleted(true)
        runProjectInfoAdd(ProjectSaveFormData)
      })
      .catch((err) => {
        console.log(err)
      })
  }

  // 不走表单校验
  const handleSaveProjectInfo = () => {
    onBeforeSave?.()   // 清除挂起的自动保存定时器
    form.validate(['objectiveId']).then((values) => {
      const fields = form.getFieldsValue()
      const projectManagerObj =
        typeof fields.projectManager === 'string'
          ? fields.projectManager
            ? [fields.projectManager]
            : []
          : fields.projectManager

      const ProjectSaveFormData = {
        ...fields,
        projectManager: projectManagerObj,
        id,
        isCompleted: false,
      }
      setSaveLoading(true)
      setIsCompleted(false)
      setProjectInfo(ProjectSaveFormData)
      runProjectInfoAdd(ProjectSaveFormData)
    })
  }

  const handleCancel = () => {
    if (isDirty) {
      Modal.confirm({
        title: t('common:confirmation'),
        content: t('project:unsavedChangesPrompt'),
        okText: t('common:btn.confirm'),
        cancelText: t('common:btn.cancel'),
        onOk: () =>
          navigate(`/projects/projects-mgmt/list`, { state: { from: 'detail' } }),
      })
    } else {
      navigate(`/projects/projects-mgmt/list`, { state: { from: 'detail' } })
    }
  }

  return (
    <div className='add-project-button'>
      {autoSaveStatus !== 'idle' && (
        <span className='auto-save-indicator'>
          {autoSaveStatus === 'unsaved' && (
            <span style={{ color: '#86909C' }}>{t('common:autoSave.unsaved')}</span>
          )}
          {autoSaveStatus === 'saving' && (
            <span style={{ color: '#86909C' }}>{t('common:autoSave.saving')}</span>
          )}
          {autoSaveStatus === 'saved' && (
            <span style={{ color: '#00B42A' }}>{t('common:autoSave.saved', { time: lastSavedTime })}</span>
          )}
          {autoSaveStatus === 'error' && (
            <span style={{ color: '#F5626C' }}>{t('common:autoSave.error')}</span>
          )}
        </span>
      )}
      <Button
        onClick={async () => {
          try {
            handleCancel()
          } catch (e) {}
        }}
      >
        {t('common:btn.cancel')}
      </Button>
      {!isProjectPublishedEdit && canProjectSave && (
        <Button
          loading={saveLoading}
          type='primary'
          disabled={
            _.isEmpty(projectDetailName) || _.isEmpty(projectDetailNameAr)
          }
          onClick={async () => {
            try {
              handleSaveProjectInfo()
            } catch (e) {}
          }}
        >
          {t('common:btn.save')}
        </Button>
      )}

      <Button
        loading={submitLoading}
        type='primary'
        onClick={async () => {
          try {
            handleSubmitProjectInfo()
          } catch (e) {}
        }}
      >
        {t('common:btn.next')}
      </Button>
    </div>
  )
}
export default ProjectAddFormBtn

