import React from 'react'
import { Button, Message, Modal } from '@arco-design/web-react'
import { useTranslation } from 'react-i18next'
import useLocaleTranslation from '@common/hooks/useLocaleTranslation'
import { isReadServerTextData } from '@common/constants/env'
import useDebouncedPromise from '@common/hooks/useDebouncedPromise'
import { initiativeInfoSave } from '@/service'
import { useRequest } from 'ahooks'
import useInitiativeInfo from '../../hooks/useInitiativeInfo'
import { useNavigate } from 'react-router-dom'
import { useState } from 'react'
import _ from 'lodash'
import './style/index.less'
import { InitiativePermissionEnum } from '@/constants/permission'
import useCheckPermission from '@common/hooks/useCheckPermission'

const InitiativesAddFormBtn = ({
  form,
  initiativeFormName,
  initiativeFormNameAr,
  setInitiativeInfoVisible,
  isAdminPublishedEdit,
  isDirty = false,
  onMarkSaved,
  onBeforeSave,
  autoSaveStatus = 'idle',
  lastSavedTime = '',
  autoSaveInitiativeIdRef,
}: {
  form: any
  initiativeFormName: string
  initiativeFormNameAr: string
  setInitiativeInfoVisible?: any
  isAdminPublishedEdit?: boolean
  isDirty?: boolean
  onMarkSaved?: () => void
  /** 手动 Save/Submit 前调用，让父组件清除自动保存定时器 */
  onBeforeSave?: () => void
  autoSaveStatus?: 'idle' | 'unsaved' | 'saving' | 'saved' | 'error'
  lastSavedTime?: string
  autoSaveInitiativeIdRef?: React.MutableRefObject<string>
}) => {
  const { t } = isReadServerTextData
    ? useLocaleTranslation()
    : useTranslation(['initiatives', 'common'])
  const {
    initiativeGeneralInfo,
    isModelEdit,
    setModelStep,
    setInitiativeId,
    setInitiativeGeneral,
    setModelStatus,
  } = useInitiativeInfo()
  const { id: storeId } = initiativeGeneralInfo
  const id = autoSaveInitiativeIdRef?.current || storeId
  const [isCompleted, setIsCompleted] = useState(false)
  const [saveLoading, setSaveLoading] = useState(false)
  const [submitLoading, setSubmitLoading] = useState(false)
  const navigate = useNavigate()

  const checkPermission = useCheckPermission()
  const canInitiativeSave = checkPermission(InitiativePermissionEnum.SAVE)

  const debouncedInitiativeInfoSave = useDebouncedPromise(
    initiativeInfoSave,
    500,
  )
  const { runAsync: runInitiativeInfoSave } = useRequest(
    debouncedInitiativeInfoSave,
    {
      manual: true,
      onSuccess: (res) => {
        onMarkSaved?.()
        Message.success(
          isCompleted
            ? t('common:message.submitSuccessfully')
            : t('common:message.saveSuccessfully'),
        )

        setInitiativeId(res)
        // 控制submit按钮跳转
        if (isCompleted) {
          // step 直接点击submit 进入step2 isModelEdit=true 弹框交互
          isModelEdit
            ? setModelStep(2)
            : navigate(`/initiatives/initiatives-mgmt/edit/2/${res}`, {
                state: { isAdminPublishedEdit: isAdminPublishedEdit },
              })
        } else {
          form.setFieldsValue({
            ...initiativeGeneralInfo,
          })
          navigate(`/initiatives/initiatives-mgmt/edit/1/${res}`)
        }
      },
      onError(e, params) {
        console.log(e)
      },
      onFinally() {
        setSaveLoading(false)
        setSubmitLoading(false)
      },
    },
  )

  // 走表单校验
  const handleSubmitInitiativesInfo = () => {
    onBeforeSave?.()   // 清除挂起的自动保存定时器
    form
      .validate()
      .then(() => {
        const fields = form.getFieldsValue()
        const initiativeSaveFormData = {
          ...fields,
          id,
          isCompleted: true,
        }
        setSubmitLoading(true)
        setIsCompleted(true)
        const updateInitiativeInfoDate = {
          ...initiativeGeneralInfo,
          ...fields,
        }
        setInitiativeGeneral(updateInitiativeInfoDate)
        runInitiativeInfoSave(initiativeSaveFormData)
      })
      .catch((err) => {
        console.log(err)
      })
  }
  // 不走表单校验
  const handleSaveInitiativesInfo = () => {
    onBeforeSave?.()   // 清除挂起的自动保存定时器
    form.validate(['objectiveId']).then((values) => {
      const fields = form.getFieldsValue()
      const initiativeSaveFormData = {
        ...fields,
        id,
        isCompleted: false,
        objectiveId: fields.objectiveId === undefined ? '' : fields.objectiveId,
      }
      setSaveLoading(true)
      setIsCompleted(false)
      setInitiativeGeneral(initiativeSaveFormData)
      runInitiativeInfoSave(initiativeSaveFormData)
    })
  }

  const handleCancel = () => {
    const doCancel = () => {
      if (isModelEdit) {
        setInitiativeInfoVisible(false)
        setModelStep(1)
        setModelStatus(false)
      } else {
        navigate(`/initiatives/initiatives-mgmt/list`, {
          state: { from: 'detail' },
        })
      }
    }
    if (isDirty) {
      Modal.confirm({
        title: t('common:confirmation'),
        content: t('project:unsavedChangesPrompt'),
        okText: t('common:btn.confirm'),
        cancelText: t('common:btn.cancel'),
        onOk: doCancel,
      })
    } else {
      doCancel()
    }
  }
  return (
    <div className='add-Initiatives-button'>
      {autoSaveStatus !== 'idle' && (
        <span className='auto-save-indicator'>
          {autoSaveStatus === 'unsaved' && (
            <span style={{ color: '#86909C' }}>{t('common:autoSave.unsaved')}</span>
          )}
          {autoSaveStatus === 'saving' && (
            <span style={{ color: '#86909C' }}>{t('common:autoSave.saving')}</span>
          )}
          {autoSaveStatus === 'saved' && (
            <span style={{ color: '#00B42A' }}>{t('common:autoSave.saved', { time: lastSavedTime })}</span>
          )}
          {autoSaveStatus === 'error' && (
            <span style={{ color: '#F5626C' }}>{t('common:autoSave.error')}</span>
          )}
        </span>
      )}
      <Button
        onClick={async () => {
          try {
            handleCancel()
          } catch (e) {}
        }}
      >
        {t('common:btn.cancel')}
      </Button>
      {!isModelEdit && !isAdminPublishedEdit && canInitiativeSave && (
        <Button
          loading={saveLoading}
          type='primary'
          disabled={
            _.isEmpty(initiativeFormName) || _.isEmpty(initiativeFormNameAr)
          }
          onClick={async () => {
            try {
              handleSaveInitiativesInfo()
            } catch (e) {}
          }}
        >
          {t('common:btn.save')}
        </Button>
      )}

      <Button
        loading={submitLoading}
        type='primary'
        onClick={async () => {
          try {
            handleSubmitInitiativesInfo()
          } catch (e) {}
        }}
      >
        {t('common:btn.next')}
      </Button>
    </div>
  )
}
export default InitiativesAddFormBtn

